#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

//======================================================================================================================================================
//======================================================================================================================================================
//		SOLVER FUNCTION
//======================================================================================================================================================
//======================================================================================================================================================

int solver(	fp** y,
					fp* x,
					int xmax,
					fp* params,
					fp* com,

					fp* d_initvalu, // CUDA specific, ignored in OpenMP
					fp* d_finavalu,
					fp* d_params,
					fp* d_com) {

	//========================================================================================================================
	//	VARIABLES
	//========================================================================================================================

	// solver parameters
	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	// memory
	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	// counters
	int i, j, k;

	//========================================================================================================================
	//		INITIAL SETUP
	//========================================================================================================================

	// solver parameters
	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	// save value for initial time instance
	x[0] = 0;

	//========================================================================================================================
	//		CHECKING
	//========================================================================================================================

	// Verify that the step size is positive and that the upper endpoint of integration is greater than the initial enpoint.               //
	if (xmin > xmax || 0.0 >= h){
		return -2;
	}

	// If the upper endpoint of the independent variable agrees with the initial value of the independent variable.  Set the value of the dependent variable and return success. //
	if (xmin == xmax){
		return 0;
	}

	// Insure that the step size h is not larger than the length of the integration interval.                                            //
	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	//========================================================================================================================
	//		SOLVING
	//========================================================================================================================

	// The outer loop iterates through time steps.
	// We can parallelize this loop if each time step's computation is independent,
	// but the solver's adaptive step size nature makes direct parallelization tricky.
	// The original CUDA code parallelized across workloads, not within a single simulation's time steps.
	// For a single simulation instance (mode 0 in main.c), this loop should remain sequential.
	for(k=1; k<=xmax; k++) {											// start after initial value

